import org.apache.nifi.processor.io.StreamCallback
import groovy.json.*

def flowFile = session.get()
if (!flowFile) return

flowFile = session.write(flowFile, { inputStream, outputStream ->

    def json = new JsonSlurper().parse(inputStream)

    // Function to clean decimal part and return STRING
    def cleanDecimal = { value ->
        if (value == null) return null

        def s = value.toString()

        // Remove everything after decimal
        if (s.contains(".")) {
            s = s.substring(0, s.indexOf("."))
        }

        return s.toInteger()  
    }

    // If JSON Array
    if (json instanceof List) {
        json.each { item ->
            item.Traffic_Volume = cleanDecimal(item.Traffic_Volume)
        }
    } 
    // If JSON Object
    else {
        json.Traffic_Volume = cleanDecimal(json.Traffic_Volume)
    }

    outputStream.write(JsonOutput.toJson(json).getBytes("UTF-8"))

} as StreamCallback)

session.transfer(flowFile, REL_SUCCESS)
